import re
import os

files_with_zrbrr = []
root = "/Users/bhyslop/projects/rbm_alpha_recipemuster/Tools/rbk"
for dirpath, dirs, files in os.walk(root):
    for fn in files:
        if not fn.endswith('.sh'):
            continue
        if fn in ('rbrr_regime.sh', 'rbrr_cli.sh'):
            continue
        p = os.path.join(dirpath, fn)
        with open(p) as fh:
            content = fh.read()
        if 'zrbrr_kindle' in content:
            files_with_zrbrr.append(p)

# Patterns:
# - source "${z_rbk_kit_dir}/rbrr_regime.sh"  -> after this, add source "${z_rbk_kit_dir}/rbrd_regime.sh" with same indent
# - source "${RBBC_rbrr_file}"  -> add source "${RBBC_rbrd_file}"
# - source "${RBBC_rbrr_file}" || buc_die "..."   -> add source "${RBBC_rbrd_file}" || buc_die "Failed to source RBRD: ${RBBC_rbrd_file}"
# - zrbrr_kindle  -> add zrbrd_kindle
# - zrbrr_enforce -> add zrbrd_enforce

def transform(content):
    lines = content.split('\n')
    out = []
    for line in lines:
        out.append(line)
        stripped = line.strip()
        # extract indent
        indent_len = len(line) - len(line.lstrip())
        indent = line[:indent_len]
        if stripped == 'source "${z_rbk_kit_dir}/rbrr_regime.sh"':
            out.append(indent + 'source "${z_rbk_kit_dir}/rbrd_regime.sh"')
        elif stripped == 'source "${RBBC_rbrr_file}"':
            out.append(indent + 'source "${RBBC_rbrd_file}"')
        elif stripped.startswith('source "${RBBC_rbrr_file}"') and '||' in stripped:
            out.append(indent + 'source "${RBBC_rbrd_file}" || buc_die "Failed to source RBRD: ${RBBC_rbrd_file}"')
        elif stripped == 'zrbrr_kindle':
            out.append(indent + 'zrbrd_kindle')
        elif stripped == 'zrbrr_enforce':
            out.append(indent + 'zrbrd_enforce')
    return '\n'.join(out)

for p in files_with_zrbrr:
    with open(p) as fh:
        c = fh.read()
    new = transform(c)
    if new != c:
        with open(p, 'w') as fh:
            fh.write(new)
        print(f"patched: {p}")
    else:
        print(f"no-change: {p}")
PYEOF

