121	/// Nameplate hallmark fields rblm_zero blanks.
122	const RBTDRP_RBRN_BLANK_FIELDS: &[&str] = &["RBRN_SENTRY_HALLMARK", "RBRN_BOTTLE_HALLMARK"];
123	
124	/// File-relative constants matching rbbc_constants.sh / rbcc_Constants.sh.
125	const RBTDRP_DOT_DIR: &str = ".rbk";
126	const RBTDRP_RBRR_FILE: &str = ".rbk/rbrr.env";
127	const RBTDRP_RBRA_FILE: &str = "rbra.env";
128	const RBTDRP_RBRN_FILE: &str = "rbrn.env";
129	const RBTDRP_RBRV_FILE: &str = "rbrv.env";
130	
131	/// BURS station-file env var (exported by bul_launcher.sh) — absolute path
132	/// to the developer's burs.env. Source for BURS_TINCTURE.
133	const RBTDRP_ENV_STATION_FILE: &str = "BURD_STATION_FILE";
134	
135	/// Read BURS_TINCTURE from the station file resolved via BURD_STATION_FILE.
136	/// BURS validation upstream (zburs_enforce) guarantees the value is 1-3 chars
137	/// of lowercase alphanumeric starting with a letter.
138	pub(crate) fn rbtdrp_burs_tincture() -> Result<String, String> {
139	    let path_str = std::env::var(RBTDRP_ENV_STATION_FILE)
140	        .map_err(|_| format!("{} not set in environment", RBTDRP_ENV_STATION_FILE))?;
141	    let path = PathBuf::from(&path_str);
142	    rbtdrp_read_env_value(&path, "BURS_TINCTURE")
143	        .ok_or_else(|| format!("BURS_TINCTURE not in {}", path.display()))
144	}
145	
146	/// Compose throwaway RBRD_CLOUD_PREFIX with the given tincture.
147	pub(crate) fn rbtdrp_throwaway_cloud_prefix(tincture: &str) -> String {
148	    format!("{}{}-", RBTDRP_THROWAWAY_CLOUD_BASE, tincture)
149	}
150	
151	/// Compose throwaway RBRR_RUNTIME_PREFIX with the given tincture.
152	pub(crate) fn rbtdrp_throwaway_runtime_prefix(tincture: &str) -> String {
153	    format!("{}{}-", RBTDRP_THROWAWAY_RUNTIME_BASE, tincture)
154	}
155	
