         source '{}/rbrr_regime.sh'\n\
         source '{}/rbgl_GarLayout.sh'\n\
         zbuv_kindle\nzrbcc_kindle\nzrbgc_kindle\n\
         source \"${{PWD}}/.rbk/rbrr.env\"\n\
