                .lines()
                .any(|l| l.trim() == expected_line);
            let runtime_ok = stdout
                .lines()
                .any(|l| l.trim() == "runtime_prefix=acme-");
            if !hallmarks_ok {
                return rbtdre_Verdict::Fail(format!(
                    "RBGL_HALLMARKS_ROOT did not match category constant; stdout:\n{}",
