            rbtdre_Verdict::Fail(format!("kindle failed (exit {}); stderr:\n{}", code, stderr))
        }
        Err(e) => rbtdre_Verdict::Fail(e),
    }
}

fn rbtdrf_rs_rbrv(dir: &Path) -> rbtdre_Verdict {
